class SummaryRanges {
    private TreeSet<Integer> nums;

    public SummaryRanges() {
        nums = new TreeSet<>();
    }

    public void addNum(int value) {
        nums.add(value);
    }

    public int[][] getIntervals() {
        List<int[]> intervals = new ArrayList<>();
        int start = -1, end = -1;
        for (int num : nums) {
            if (start == -1) {
                start = end = num;
            } else if (num == end + 1) {
                end = num;
            } else {
                intervals.add(new int[] {start, end});
                start = end = num;
            }
        }
        if (start != -1) {
            intervals.add(new int[] {start, end});
        }
        return intervals.toArray(new int[0][]);
    }
}

